     1→/*
     2→ * fmod() test harness — prints (x_hex, y_hex, output_hex) triples.
     3→ */
     4→
     5→#include <math.h>
     6→#include <stdint.h>
     7→#include <stdio.h>
     8→#include <float.h>
     9→
    10→static inline uint64_t d2u(double d)
    11→{
    12→    union { double d; uint64_t u; } x;
    13→    x.d = d;
    14→    return x.u;
    15→}
    16→
    17→static inline double u2d(uint64_t u)
    18→{
    19→    union { double d; uint64_t u; } x;
    20→    x.u = u;
    21→    return x.d;
    22→}
    23→
    24→static void emit(double x, double y)
    25→{
    26→    double r = fmod(x, y);
    27→    printf("%016llx %016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(y), (unsigned long long)d2u(r));
    28→}
    29→
    30→static void emit_u(uint64_t x_bits, uint64_t y_bits)
    31→{
    32→    emit(u2d(x_bits), u2d(y_bits));
    33→}
    34→
    35→/* Test special values */
    36→static void test_special(void)
    37→{
    38→    emit(0.0, 1.0);
    39→    emit(-0.0, 1.0);
    40→    emit(1.0, 0.0);
    41→    emit_u(0x7ff8000000000000ULL, 0x3ff0000000000000ULL);  /* NaN, 1.0 */
    42→    emit_u(0x3ff0000000000000ULL, 0x7ff8000000000000ULL);  /* 1.0, NaN */
    43→    emit_u(0x7ff0000000000000ULL, 0x3ff0000000000000ULL);  /* +Inf, 1.0 */
    44→    emit(1.0, INFINITY);
    45→}
    46→
    47→/* Test normal cases */
    48→static void test_normal(void)
    49→{
    50→    emit(5.0, 2.0);
    51→    emit(5.5, 2.5);
    52→    emit(-5.0, 2.0);
    53→    emit(5.0, -2.0);
    54→    emit(-5.0, -2.0);
    55→    emit(1.5, 0.5);
    56→    emit(3.0, 2.0);
    57→}
    58→
    59→/* Test small operands */
    60→static void test_small(void)
    61→{
    62→    emit(0.1, 0.3);
    63→    emit(1.0e-100, 1.0e-50);
    64→    emit(1.0e-20, 1.0e-10);
    65→    emit(DBL_MIN, 1.0);
    66→}
    67→
    68→/* Test large operands */
    69→static void test_large(void)
    70→{
    71→    emit(1e100, 1e50);
    72→    emit(1e200, 1e100);
    73→    emit(DBL_MAX, 1e100);
    74→}
    75→
    76→/* Test various ratios */
    77→static void test_ratios(void)
    78→{
    79→    emit(10.0, 3.0);
    80→    emit(7.0, 2.5);
    81→    emit(22.0, 7.0);
    82→    emit(100.0, 30.0);
    83→}
    84→
    85→int main(void)
    86→{
    87→    test_special();
    88→    test_normal();
    89→    test_small();
    90→    test_large();
    91→    test_ratios();
    92→    return 0;
    93→}
